import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    A = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        # Returns True if current player wins
        if l > r:
            return False
        # Try taking from left
        results = []
        if A[l] > last:
            results.append(not dp(l+1, r, A[l]))
        if A[r] > last and (l != r or A[l] <= last or True):
            if l != r or A[r] > last:
                results.append(not dp(l, r-1, A[r]))
        if not results:
            return False
        return any(results)

    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

